-- ============================================
-- Legislacao full-site: thiago-de-joaldo / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/220560
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = thiago-de-joaldo-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 63
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=220560, tipo Deputado(a), ordemAssinatura=1.
-- 37 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'thiago-de-joaldo';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'thiago-de-joaldo: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao thiago-de-joaldo: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2611359', '2611024', '2609830', '2609638', '2591498', '2586705', '2569253', '2600831', '2582236', '2581991', '2571048', '2563536', '2562277', '2558239', '2554483', '2550182', '2548423', '2592837', '2586678', '2584173', '2582233', '2571680', '2569275', '2565925', '2564314', '2563264', '2561275', '2554565', '2554480', '2548887', '2586672', '2576587', '2571083', '2565918', '2563202', '2558240', '2554486', '2552721', '2548427', '2582235', '2579604', '2570896', '2564464', '2561924', '2558238', '2556070', '2554482', '2549597', '2548419', '2584533', '2582234', '2567124', '2565926', '2564461', '2563267', '2561923', '2558237', '2555502', '2548892', '2609826', '2603142', '2586698', '2554481');
  IF target_present <> 63 THEN
    RAISE EXCEPTION 'Pre-condicao thiago-de-joaldo: esperadas 63 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2611359', '2611024', '2609830', '2609638', '2591498', '2586705', '2569253', '2600831', '2582236', '2581991', '2571048', '2563536', '2562277', '2558239', '2554483', '2550182', '2548423', '2592837', '2586678', '2584173', '2582233', '2571680', '2569275', '2565925', '2564314', '2563264', '2561275', '2554565', '2554480', '2548887', '2586672', '2576587', '2571083', '2565918', '2563202', '2558240', '2554486', '2552721', '2548427', '2582235', '2579604', '2570896', '2564464', '2561924', '2558238', '2556070', '2554482', '2549597', '2548419', '2584533', '2582234', '2567124', '2565926', '2564461', '2563267', '2561923', '2558237', '2555502', '2548892', '2609826', '2603142', '2586698', '2554481')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'thiago-de-joaldo-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao thiago-de-joaldo: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao thiago-de-joaldo: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

